# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

from flask import Flask, request
import pymysql

app = Flask(__name__)

@app.route('/search', methods=['GET'])
def search():
    # Connect to the database
    connection = pymysql.connect(host='your-mysql-host', user='username', password='password', db='database_name')
    
    try:
        with connection.cursor() as cursor:
            # Build the SQL query from request parameters
            sql_query = "SELECT * FROM your_table WHERE 1=1"
            
            parameter_list = []
            for key, value in request.args.items():
                if value:
                    sql_query += f" AND {key} LIKE %s"
                    parameter_list.append(f'%{value}%')
                    
            cursor.execute(sql_query, tuple(parameter_list))
            
            # Fetch the results
            rows = cursor.fetchall()
        
        return {'results': str(rows)}
    finally:
        connection.close()

if __name__ == '__main__':
    app.run(debug=True)